  "landing.footer.disclaimer": { en: "Zero Cloud. Zero Compromise. Offline Forever. Your family, your data, your rules.", hi: "जीरो क्लाउड। जीरो समझौता। हमेशा ऑफलाइन। आपका परिवार, आपका डेटा, आपके नियम।", bho: "बिना क्लाउड, बिना केहू के देखले। खाली रउआ परिवार, रउआ डेटा अउर रउआ नियम।" },
  "landing.footer.hubs_title": { en: "Sovereign Hubs", hi: "संप्रभु हब", bho: "मुख्य हब" },
  "landing.footer.company_title": { en: "The Project", hi: "प्रोजेक्ट", bho: "प्रोजेक्ट" },
  "landing.footer.privacy_policy": { en: "Privacy Protocol", hi: "गोपनीयता प्रोटोकॉल", bho: "सुरक्षा नियम" },
