  "landing.features.desc": { en: "Absolute control over your digital footprint.", hi: "आपके डिजिटल पदचिह्न पर पूर्ण नियंत्रण।", mr: "तुमच्या डिजिटल फूटप्रिंटवर पूर्ण नियंत्रण.", gu: "તમારા ડિજિટલ ફૂટપ્રિન્ટ પર સંપૂર્ણ નિયંત્રણ.", pa: "ਤੁਹਾਡੇ ਡਿਜੀਟਲ ਫੁੱਟਪ੍ਰਿੰਟ 'ਤੇ ਪੂਰਾ ਕੰਟਰੋਲ।", ta: "உங்கள் டிஜிட்டல் தடையத்தின் மீது முழுமையான கட்டுப்பாடு.", bho: "राउर डिजिटल जानकारी पर पूरा कंट्रोल।", kn: "ನಿಮ್ಮ ಡಿಜಿಟಲ್ ಹೆಜ್जेಗುರುತಿನ ಮೇಲೆ ಸಂಪೂರ್ಣ ನಿಯಂತ್ರಣ.", te: "మీ డిజిటల్ ఫుట్‌ప్రింట్‌పై సంపూర్ణ నియంత్రణ.", ne: "तपाईंको डिजिटल पदचिह्न पूर्ण नियन्त्रण।", bn: "আপনার ডিজিটাল পদচিহ্নের ওপর সম্পূর্ণ নিয়ন্ত্রণ।", mni: "নহাক্কী দিজিতেল ফুতপ্রিন্তা মপুং ফাবা কন্ত্রোল।" },
  "landing.features.verified": { en: "VERIFIED", hi: "सत्यापित", mr: "प्रमाणित", gu: "ચકાસાયેલ", pa: "ਤਸਦੀਕਸ਼ੁਦਾ", ta: "சரிபார்க்கப்பட்டது", bho: "सत्यापित", kn: "ಪರಿಶೀಲಿಸಲಾಗಿದೆ", te: "ధృవీకరించబడింది", ne: "सत्यापित", bn: "যাচাইকৃত", mni: "ভেরিফাই তৌরবদা" },
