  // Product Page Manifesto
  "product.manifesto.title": { en: "The Hardware of Heritage", hi: "\u0935\u093f\u0930\u093e\u0938\u0924 \u0915\u093e \u0939\u093e\u0930\u094d\u0921\u0935\u0947\u092f\u0930", mr: "\u0935\u093e\u0930\u0936\u093e\u091a\u0947 \u0939\u093e\u0930\u094d\u0921\u0935\u0947\u0905\u0930", gu: "\u0ab5\u0abe\u0ab0\u0ab8\u0abe\u0aa8\u0ac1\u0a82 \u0ab9\u0abe\u0ab0\u0acd\u0aa1\u0ab5\u0ac7\u0ab0", pa: "\u0a35\u0a3f\u0a30\u0a3e\u0a38\u0a24 \u0a26\u0a3e \u0a39\u0a3e\u0a30\u0a21\u0a35\u0a47\u0a05\u0a30", ta: "\u0baa\u0bbe\u0bb0\u0bae\u0bcd\u0baa\u0bb0\u0bbf\u0baf\u0ba4\u0bcd\u0ba4\u0bbf\u0ba9\u0bcd \u0bb5\u0ba9\u0bcd\u0baa\u0bca\u0bb0\u0bc1\u0bb3\u0bcd", bho: "\u0935\u093f\u0930\u093e\u0938\u0924 \u0915\u0947 \u0939\u093e\u0930\u094d\u0921\u0935\u0947\u092f\u0930", kn: "\u0caa\u0cb0\u0c82\u0caa\u0cb0\u0cc6\u0caf \u0cb9\u0cbe\u0cb0\u0ccd\u0ca1\u0ccd\u200c\u0cb5\u0cc7\u0cb0\u0ccd", te: "\u0c35\u0c3e\u0c30\u0c38\u0c24\u0c4d\u0c35 \u0c39\u0c3e\u0c30\u0c4d\u0c21\u0c4d\u0c35\u0c47\u0c30\u0c4d", ne: "\u0935\u093f\u0930\u093e\u0938\u0924\u0915\u094b \u0939\u093e\u0930\u094d\u0921\u0935\u0947\u092f\u0930", bn: "\u0990\u09a4\u09bf\u09b9\u09cd\u09af\u09c7\u09b0 \u09b9\u09be\u09b0\u09cd\u09a1\u0993\u09af\u09bc\u09cd\u09af\u09be\u09b0", mni: "\u09b9\u09c7\u09b0\u09bf\u09a4\u09c7\u099c\u0997\u09c0 \u09b9\u09be\u09b0\u09cd\u09a6\u0993\u09af\u09bc\u09cd\u09af\u09be\u09b0" },
  "product.manifesto.sub": { 
    en: "Sovereign OS is not a web app. It is a local runtime built for multigenerational security.", 
    hi: "\u0938\u0949\u0935\u0930\u0947\u0928 \u0913\u090f\u0938 \u090f\u0915 \u0935\u0947\u092c \u0910\u092a \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 \u092f\u0939 \u092c\u0939\u0941-\u092a\u0940\u0922\u093c\u0940\u0917\u0924 \u0938\u0941\u0930\u0915\u094d\u0937\u093e \u0915\u0947 \u0932\u093f\u090f \u092c\u0928\u093e\u092f\u093e \u0917\u092f\u093e \u090f\u0915 \u0932\u094b\u0915\u0932 \u0930\u0928\u091f\u093e\u0907\u092e \u0939\u0948\u0964",
    mr: "\u0938\u093e\u0930\u094d\u0935\u092d\u094c\u092e \u0913\u090f\u0938 \u0939\u0947 \u0935\u0947\u092c \u0972\u092a \u0928\u093e\u0939\u0940. \u0939\u0947 \u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u0930\u0928\u091f\u093e\u0907\u092e \u0906\u0939\u0947.",
    gu: "\u0ab8\u0acb\u0ab5\u0ab0\u0abf\u0aa8 \u0a93\u0a8f\u0ab8 \u0ab5\u0ac7\u0aac \u0a8f\u0aaa \u0aa8\u0aa5\u0ac0. \u0aa4\u0ac7 \u0ab8\u0acd\u0aa5\u0abe\u0aa8\u0abf\u0a95 \u0ab0\u0aa8\u0a9f\u0abe\u0a87\u0aae \u0a9b\u0ac7.",
    pa: "\u0a38\u0a3e\u0a35\u0a30\u0a47\u0a28 \u0a13\u0a10\u0a38 \u0a15\u0a4b\u0a08 \u0a35\u0a48\u0a71\u0a2c \u0a10\u0a2a \u0a28\u0a39\u0a40\u0a02 \u0a39\u0a48\u0964 \u0a07\u0a39 \u0a07\u0a71\u0a15 \u0a32\u0a4b\u0a15\u0a32 \u0a30\u0a28\u0a1f\u0a3e\u0a08\u0a2e \u0a39\u0a48\u0964",
    ta: "\u0b87\u0bb1\u0bc8\u0baf\u0bbe\u0ba3\u0bcd\u0bae\u0bc8 \u0b93\u0b8e\u0bb8\u0bcd \u0b92\u0bb0\u0bc1 \u0b87\u0ba3\u0bc8\u0baf\u0ba4\u0bb3\u0bae\u0bcd \u0b85\u0bb2\u0bcd\u0bb2. \u0b87\u0ba4\u0bc1 \u0b89\u0bb3\u0bcd\u0bb3\u0bc2\u0bb0\u0bcd \u0b87\u0baf\u0b99\u0bcd\u0b95\u0bc1\u0ba4\u0bb3\u0bae\u0bcd.",
    bho: "\u0908 \u0915\u094c\u0928\u094b\u0902 \u0935\u0947\u092c \u0910\u092a \u0928\u093e\u0939\u0940 \u0939\u0935\u0947, \u0908 \u0932\u094b\u0915\u0932 \u0930\u0928\u091f\u093e\u0907\u092e \u0939\u0935\u0947\u0964",
    kn: "\u0cb8\u0cca\u0cb5\u0cb0\u0cbf\u0ca8\u0ccd \u0c93\u0c8e\u0cb8\u0ccd \u0c95\u0cc7\u0cb5\u0cb2 \u0cb5\u0cc6\u0cac\u0ccd \u0c86\u0caa\u0ccd \u0c85\u0cb2\u0ccd\u0cb2. \u0c87\u0ca6\u0cc1 \u0cb8\u0ccd\u0ca5\u0cb3\u0cc0\u0caf \u0cb0\u0ca8\u0ccd\u200c\u0c9f\u0cc8\u0cae\u0ccd \u0c86\u0c97\u0cbf\u0ca6\u0cc6.",
    te: "\u0c38\u0c3e\u0c35\u0c30\u0c40\u0c28\u0c4d OS \u0c35\u0c46\u0c2c\u0c4d \u0c2f\u0c3e\u0c2a\u0c4d \u0c15\u0c3e\u0c26\u0c41. \u0c07\u0c26\u0c3f \u0c32\u0c4b\u0c15\u0c32\u0c4d \u0c30\u0c28\u0c4d\u200c\u0c1f\u0c48\u0c2e\u0c4d.",
    ne: "\u09b8\u09ac\u09c7\u09b0\u09bf\u09a8 \u0993\u098f\u09b8 \u0993\u09df\u09c7\u09ac \u098f\u09aa \u09b9\u09df\u09a8\u0964 \u092f\u094b \u0938\u094d\u0925\u093e\u0928\u0940\u092f \u0930\u0928\u091f\u093e\u0907\u092e \u0939\u094b\u0964",
    bn: "\u09b8\u09be\u09b0\u09cd\u09ac\u09ad\u09cc\u09ae \u0993\u098f\u09b8 \u0995\u09cb\u09a8\u09cb \u0993\u09af\u09bc\u09c7\u09ac \u0985\u09cd\u09af\u09be\u09aa \u09a8\u09af\u09bc\u0964 \u098f\u099f\u09bf \u09ac\u09b9\u09c1\u09aa\u099c\u09a8\u09cd\u09ae\u09c7\u09b0 \u099c\u09a8\u09cd\u09af \u09a4\u09c8\u09b0\u09bf \u098f\u0995\u099f\u09bf \u09b2\u09cb\u0995\u09be\u09b2 \u09b0\u09be\u09a8\u099f\u09be\u0987\u09ae\u0964",
    mni: "\u09b8\u09cb\u09ad\u09b0\u09bf\u09a8 \u0993\u098f\u09b8 \u0985\u09b8\u09bf \u0985\u09ae\u09a4\u09cd\u09a4\u09be \u0993\u0987\u09ac\u09be \u09a8\u09a4\u09cd\u09a4\u09c7\u0964"
  },

